import PDFDocument from "pdfkit";
import qr from "qrcode";
import type { Prisma } from "#server/prisma/generated/prisma/browser";
import { getEventBadgeLogoPath } from "./settings";

type Participant = Prisma.ParticipantGetPayload<{
  include: {
    user: true,
    team: true,
  }
}>
type Admin = Prisma.AdminGetPayload<{
  include: {
    user: true,
  }
}>
type Guest = Prisma.GuestGetPayload<object>;
type Sponsor = Prisma.SponsorGetPayload<object>;
type BadgeGridEntry = (doc: PDFKit.PDFDocument, origin: Coordinates) => Promise<void>;
type BadgeContentDrawHandler = () => Promise<void>;

type LayoutCircleOptions = {
  pos: Coordinates;
  radius: number;
};

type Coordinates = [x: number, y: number];
type LoadedStorageImage = {
  cacheKey: string;
  buffer: Buffer;
};
type OpenedPdfImage = {
  width: number;
  height: number;
  label: string;
  obj?: unknown;
  orientation?: number;
  embed: (doc: PDFKit.PDFDocument) => void;
};

interface TextLine {
  text: string;
  fontSize: number;
  color: string;
  gapAfter?: boolean;
}

interface MeasuredTextLine extends TextLine {
  height: number;
  fittedFontSize: number;
}

interface DrawBadgeTextBlockOptions {
  circle?: LayoutCircleOptions;
  minimumLeftX?: number;
  maximumRightX?: number;
  circleSafeMargin?: number;
  textRightPadding?: number;
  textVerticalPadding?: number;
  baseTextGap?: number;
  origin?: Coordinates;
}

const BADGE_SIZE: Coordinates = [cmToPoints(10), cmToPoints(5)] as const;
const A4_SIZE: Coordinates = [cmToPoints(21), cmToPoints(29.7)] as const;
const A4_BADGE_GRID = {
  columns: 2,
  rows: 5,
} as const;

const BADGE_PRIMARY_COLOR = "#227d50";
const BADGE_BACKGROUND_COLOR = "#ecfff4";

const remoteImageCache = new Map<string, Promise<LoadedStorageImage | null>>();

