//region Main functions
/**
 * Renders a grid of badges on A4 sheets, given an array of badge drawing functions and a title for the PDF document.
 * Each badge drawing function is responsible for drawing a single badge at a specified origin on the PDF document.
 *
 * @param entries An array of functions that draw badges on the PDF document, each function takes a PDFDocument instance and an origin coordinate as parameters
 * @param title The title to set in the PDF document metadata
 * @returns A PDFDocument instance containing the rendered badge grid, ready to be piped or saved to a file
 */
async function renderBadgeGridEntries(entries: BadgeGridEntry[], title: string): Promise<PDFKit.PDFDocument> {
  const doc = createBadgesDocument(A4_SIZE, title);
  const badgesPerPage = A4_BADGE_GRID.columns * A4_BADGE_GRID.rows;
  await loadEventBadgeLogoSource();

  for (const [index, drawBadge] of entries.entries()) {
    const slotIndex = index % badgesPerPage;

    if (slotIndex === 0) {
      doc.addPage({size: A4_SIZE, margin: 0});
    }

    await drawBadge(doc, getBadgeGridOrigin(slotIndex));
  }

  doc.end();

  return doc;
}

async function renderSingleBadge(title: string, drawBadge: (doc: PDFKit.PDFDocument) => Promise<void>): Promise<PDFKit.PDFDocument> {
  const doc = createBadgesDocument(BADGE_SIZE, title);
  await loadEventBadgeLogoSource();

  doc.addPage({size: BADGE_SIZE, margin: 0});
  await drawBadge(doc);

  doc.end();

  return doc;
}

function drawBadgeCutGuide(doc: PDFKit.PDFDocument, size: Coordinates = BADGE_SIZE, origin: Coordinates = [0, 0]) {
  const [pageWidth, pageHeight] = size;
  const [originX, originY] = origin;

  doc.save();
  doc.lineWidth(.75);
  doc.dash(cmToPoints(.12), {space: cmToPoints(.08)});
  doc.strokeColor("#7c9a8a");
  doc.rect(originX, originY, pageWidth, pageHeight).stroke();
  doc.restore();
}

function drawCircularImage(doc: PDFKit.PDFDocument, imageSource: LoadedStorageImage, circle: LayoutCircleOptions, origin: Coordinates = [0, 0]) {
  const image = openCachedPdfImage(doc, imageSource);
  const center = addCoordinates(origin, circle.pos);
  const imagePadding = cmToPoints(.3);
  const [imageWidth, imageHeight] = fitImageWithinBox(
    image.width,
    image.height,
    (circle.radius * 2) - (imagePadding * 2),
    (circle.radius * 2) - (imagePadding * 2),
  );

  doc.save();
  doc.fillColor("#ffffff");
  doc.circle(center[0], center[1], circle.radius).fill();
  doc.circle(center[0], center[1], circle.radius - cmToPoints(.03)).clip();
  doc.image(image as any, center[0] - (imageWidth / 2), center[1] - (imageHeight / 2), {
    width: imageWidth,
    height: imageHeight,
  });
  doc.restore();

  doc.save();
  doc.lineWidth(.75);
  doc.strokeColor(BADGE_PRIMARY_COLOR);
  doc.circle(center[0], center[1], circle.radius).stroke();
  doc.restore();
}

async function drawBadgeFrame(doc: PDFKit.PDFDocument, drawContent: BadgeContentDrawHandler, size: Coordinates = BADGE_SIZE, origin: Coordinates = [0, 0], drawCutGuide = false, circle = getDefaultBadgeCircle(size)) {
  const [pageWidth, pageHeight] = size;
  const [originX, originY] = origin;

  doc.save();
  doc.rect(originX, originY, pageWidth, pageHeight).clip();

  await drawBadgeLayout(doc, size, circle, origin);
  await drawContent();
  doc.restore();

  if (drawCutGuide) {
    drawBadgeCutGuide(doc, size, origin);
  }
}

//region Draw functions
/**
 * Creates the common layout for a badge, including the background, the logo circle and the logo itself.
 *
 * @param doc The PDFDocument instance to draw on
 * @param size The size of the page in points
 * @param circle Optional parameters for the logo circle, including its position and radius. If not provided, default values based on the page size will be used.
 */
async function drawBadgeLayout(doc: PDFKit.PDFDocument, size: Coordinates = BADGE_SIZE, circle = getDefaultBadgeCircle(size), origin: Coordinates = [0, 0]) {
  const [pageWidth, pageHeight] = size;
  const [originX, originY] = origin;

  doc.rect(originX, originY, pageWidth, pageHeight).fillColor(BADGE_BACKGROUND_COLOR).fill();

  doc.fillColor(BADGE_PRIMARY_COLOR);

  //region Logo and circle
  const circleCenter = addCoordinates(origin, circle.pos);
  doc.circle(circleCenter[0], circleCenter[1], circle.radius).fill();

  const eventLogoSource = await loadEventBadgeLogoSource();

  if (eventLogoSource) {
    const logo = openCachedPdfImage(doc, eventLogoSource);
    const logoWidth = circle.radius * .9;
    const logoHeight = logoWidth * (logo.height / logo.width);
    const [logoCenterX, logoCenterY] = await visibleCircleCentroid(
      size,
      circle.pos,
      circle.radius,
    );
    const logoPos: Coordinates = [
      logoCenterX - logoWidth / 2,
      logoCenterY - logoHeight / 2,
    ];
    const absoluteLogoPos = addCoordinates(origin, logoPos);
    doc.image(logo as any, absoluteLogoPos[0], absoluteLogoPos[1], {
      width: logoWidth,
    });
  }
  //endregion
}

/**
 * Creates a badge for a participant, including the common layout, the QR code and the participant's information text.
 *
 * @param doc The PDFDocument instance to draw on
 * @param participant The participant for whom to create the badge
 * @param size The size of the page in points
 */
async function drawParticipantBadge(doc: PDFKit.PDFDocument, participant: Participant, size: Coordinates = BADGE_SIZE, origin: Coordinates = [0, 0], drawCutGuide = false) {
  await drawBadgeFrame(doc, async () => {
    const [, pageHeight] = size;
    const qrcode = await qr.toBuffer(participant.userId, {margin: 0, color: {light: BADGE_BACKGROUND_COLOR}});
    const qrcodeSize = pageHeight * .4;
    const qrcodeMargin = cmToPoints(.25);
    const qrcodePos: Coordinates = [qrcodeMargin, pageHeight - qrcodeSize - qrcodeMargin];
    const absoluteQrCodePos = addCoordinates(origin, qrcodePos);
    doc.image(qrcode, absoluteQrCodePos[0], absoluteQrCodePos[1], {
      width: qrcodeSize,
      height: qrcodeSize,
      align: "center",
    });

    const qrcodeSafeMargin = cmToPoints(.5);
    const textLines: TextLine[] = [
      {
        text: `${participant.user.firstName} ${participant.user.lastName}`.trim(),
        fontSize: 20,
        color: BADGE_PRIMARY_COLOR,
        gapAfter: false,
      },
      {text: "Participant", fontSize: 16, color: BADGE_PRIMARY_COLOR},
      participant.team
        ? {text: `Team ${participant.team.name}`, fontSize: 14, color: BADGE_PRIMARY_COLOR}
        : {text: "Sans équipe", fontSize: 14, color: "#ff0000"},
      ...(participant.school
        ? [{text: participant.school, fontSize: 12, color: BADGE_PRIMARY_COLOR}]
        : []),
    ];

    drawBadgeTextBlock(doc, size, textLines, {
      minimumLeftX: qrcodePos[0] + qrcodeSize + qrcodeSafeMargin,
      origin,
    });
    doc.fillColor(BADGE_PRIMARY_COLOR);
  }, size, origin, drawCutGuide);
}

async function drawAdminBadge(doc: PDFKit.PDFDocument, admin: Admin, size: Coordinates = BADGE_SIZE, origin: Coordinates = [0, 0], drawCutGuide = false) {
  await drawBadgeFrame(doc, async () => {
    drawBadgeTextBlock(doc, size, [
      {
        text: `${admin.user.firstName} ${admin.user.lastName}`.trim(),
        fontSize: 20,
        color: BADGE_PRIMARY_COLOR,
        gapAfter: false,
      },
      {text: "Staff", fontSize: 16, color: BADGE_PRIMARY_COLOR},
    ], {origin});
    doc.fillColor(BADGE_PRIMARY_COLOR);
  }, size, origin, drawCutGuide);
}

async function drawSponsorBadge(doc: PDFKit.PDFDocument, sponsor: Sponsor, size: Coordinates = BADGE_SIZE, origin: Coordinates = [0, 0], drawCutGuide = false) {
  const sponsorLogoCircle = getSponsorLogoCircle(size);
  const sponsorLogo = await loadStorageImage(sponsor.logo, SPONSORS_BUCKET);

  await drawBadgeFrame(doc, async () => {
    const [, pageHeight] = size;

    const qrcodeSafeMargin = cmToPoints(.5);
    const qrcode = await qr.toBuffer(sponsor.url, {margin: 0, color: {light: BADGE_BACKGROUND_COLOR}});
    const qrcodeSize = pageHeight * .4;
    const qrcodeMargin = cmToPoints(.25);
    const qrcodePos: Coordinates = [qrcodeMargin, pageHeight - qrcodeSize - qrcodeMargin];
    const absoluteQrCodePos = addCoordinates(origin, qrcodePos);
    doc.image(qrcode, absoluteQrCodePos[0], absoluteQrCodePos[1], {
      width: qrcodeSize,
      height: qrcodeSize,
      align: "center",
    });

    if (sponsorLogo) {
      drawCircularImage(doc, sponsorLogo, sponsorLogoCircle, origin);
    }

    drawBadgeTextBlock(doc, size, [
      {text: sponsor.name, fontSize: sponsorLogo ? 18 : 20, color: BADGE_PRIMARY_COLOR},
    ], {
      minimumLeftX: qrcodePos[0] + qrcodeSize + qrcodeSafeMargin,
      maximumRightX: sponsorLogo
        ? sponsorLogoCircle.pos[0] - sponsorLogoCircle.radius - cmToPoints(.35)
        : undefined,
      origin,
    });

    doc.fillColor(BADGE_PRIMARY_COLOR);
  }, size, origin, drawCutGuide);
}

async function drawGuestBadge(doc: PDFKit.PDFDocument, guest: Guest, size: Coordinates = BADGE_SIZE, origin: Coordinates = [0, 0], drawCutGuide = false) {
  await drawBadgeFrame(doc, async () => {
    drawBadgeTextBlock(doc, size, [
      {text: guest.name, fontSize: 20, color: BADGE_PRIMARY_COLOR, gapAfter: false},
      {text: translateGuestType(guest.type), fontSize: 16, color: BADGE_PRIMARY_COLOR, gapAfter: !guest.company},
      ...(guest.company ? [{text: guest.company, fontSize: 14, color: BADGE_PRIMARY_COLOR}] : []),
    ], {origin});
    doc.fillColor(BADGE_PRIMARY_COLOR);
  }, size, origin, drawCutGuide);
}

//endregion

//region Render functions
export async function renderParticipantBadge(participant: Participant): Promise<PDFKit.PDFDocument> {
  return renderSingleBadge(`Badge de ${participant.user.firstName} ${participant.user.lastName}`, async (doc) => drawParticipantBadge(doc, participant, BADGE_SIZE));
}

export async function renderAdminBadge(admin: Admin): Promise<PDFKit.PDFDocument> {
  return renderSingleBadge(`Badge de ${admin.user.firstName} ${admin.user.lastName}`, async (doc) => drawAdminBadge(doc, admin, BADGE_SIZE));
}

/**
 * Renders a PDF document containing participant badges arranged on A4 sheets, with team participants rendered first.
 *
 * @param participants An array of participants to render badges for
 * @returns A PDFDocument instance containing the rendered badges for all participants
 */
export async function renderParticipantsBadges(participants: Participant[]): Promise<PDFKit.PDFDocument> {
  const orderedParticipants = getOrderedParticipants(participants);

  return renderBadgeGridEntries(
    toBadgeGridEntries(orderedParticipants, async (doc, participant, origin) => drawParticipantBadge(doc, participant, BADGE_SIZE, origin, true)),
    "Badges des participants",
  );
}

export async function renderSponsorBadge(sponsor: Sponsor): Promise<PDFKit.PDFDocument> {
  return renderSingleBadge(`Badge de ${sponsor.name}`, async (doc) => drawSponsorBadge(doc, sponsor, BADGE_SIZE));
}

export async function renderSponsorsBadges(sponsors: Sponsor[]): Promise<PDFKit.PDFDocument> {
  return renderBadgeGridEntries(
    toBadgeGridEntries(sponsors, async (doc, sponsor, origin) => drawSponsorBadge(doc, sponsor, BADGE_SIZE, origin, true)),
    "Badges des sponsors",
  );
}

export async function renderGuestBadge(guest: Guest): Promise<PDFKit.PDFDocument> {
  return renderSingleBadge(`Badge de ${guest.name}`, async (doc) => drawGuestBadge(doc, guest, BADGE_SIZE));
}

export async function renderGuestsBadges(guests: Guest[]): Promise<PDFKit.PDFDocument> {
  const expandedGuests = getExpandedGuests(guests);

  return renderBadgeGridEntries(
    toBadgeGridEntries(expandedGuests, async (doc, guest, origin) => drawGuestBadge(doc, guest, BADGE_SIZE, origin, true)),
    "Badges des invités",
  );
}

export async function renderAllBadges(participants: Participant[], guests: Guest[], sponsors: Sponsor[], admins: Admin[]): Promise<PDFKit.PDFDocument> {
  const orderedParticipants = getOrderedParticipants(participants);
  const expandedGuests = getExpandedGuests(guests);
  const sponsorsWithBadge = sponsors.filter((sponsor) => sponsor.hasBadge);

  return renderBadgeGridEntries([
    ...toBadgeGridEntries(orderedParticipants, async (doc, participant, origin) => drawParticipantBadge(doc, participant, BADGE_SIZE, origin, true)),
    ...toBadgeGridEntries(expandedGuests, async (doc, guest, origin) => drawGuestBadge(doc, guest, BADGE_SIZE, origin, true)),
    ...toBadgeGridEntries(sponsorsWithBadge, async (doc, sponsor, origin) => drawSponsorBadge(doc, sponsor, BADGE_SIZE, origin, true)),
    ...toBadgeGridEntries(admins, async (doc, admin, origin) => drawAdminBadge(doc, admin, BADGE_SIZE, origin, true)),
  ], "Tous les badges");
}

